class Solution:
    def maxRepOpt1(self, text):
        def longest_run(s):
            best = cur = 1
            for i in range(1, len(s)):
                if s[i] == s[i - 1]:
                    cur += 1
                    best = max(best, cur)
                else:
                    cur = 1
            return best if s else 0
        chars = list(text)
        best = longest_run(text)
        n = len(chars)
        for i in range(n):
            for j in range(i + 1, n):
                if chars[i] == chars[j]:
                    continue
                chars[i], chars[j] = chars[j], chars[i]
                best = max(best, longest_run(''.join(chars)))
                chars[i], chars[j] = chars[j], chars[i]
        return best

