var maxRepOpt1 = function(text) {
    const total = {};
    for (const c of text) total[c] = (total[c] || 0) + 1;
    const runs = [];
    let i = 0;
    const n = text.length;
    while (i < n) {
        let j = i;
        while (j < n && text[j] === text[i]) j++;
        runs.push([text[i], j - i]);
        i = j;
    }
    let best = 0;
    for (let idx = 0; idx < runs.length; idx++) {
        const ch = runs[idx][0], length = runs[idx][1];
        best = Math.max(best, Math.min(length + 1, total[ch]));
        if (idx + 2 < runs.length && runs[idx + 1][1] === 1 && runs[idx + 2][0] === ch) {
            const merged = length + runs[idx + 2][1];
            best = Math.max(best, Math.min(merged + 1, total[ch]));
        }
    }
    return best;
};
